INSERT INTO public.earning_projects (owner_id, title, description, tags, budget_min, budget_max, deadline_days, location, status) VALUES
('854913e6-6f3f-4d4e-9ac8-5b1d0169ba5b', 'Literature Review: AI in Healthcare', 'Comprehensive literature review covering recent advances in AI applications for healthcare diagnostics. Must include at least 30 peer-reviewed sources from 2020-2025.', ARRAY['AI', 'Healthcare', 'Literature Review'], 5000, 15000, 14, 'Remote', 'open'),
('854913e6-6f3f-4d4e-9ac8-5b1d0169ba5b', 'Statistical Analysis for Survey Data', 'Need SPSS analysis for a 200-respondent survey on student mental health. Includes descriptive stats, correlation, and regression analysis with interpretation.', ARRAY['SPSS', 'Statistics', 'Data Analysis'], 8000, 20000, 10, 'Remote', 'open'),
('854913e6-6f3f-4d4e-9ac8-5b1d0169ba5b', 'Python Script for Web Scraping', 'Build a Python web scraper to collect publication data from Google Scholar for a specific research domain. Output as clean CSV with title, authors, year, citations.', ARRAY['Python', 'Web Scraping', 'Automation'], 3000, 10000, 7, 'Remote', 'open'),
('854913e6-6f3f-4d4e-9ac8-5b1d0169ba5b', 'Research Poster Design', 'Design an academic research poster (A0 size) for a conference presentation on renewable energy. Content will be provided; need professional layout and visuals.', ARRAY['Design', 'Academic', 'LaTeX'], 2000, 8000, 5, 'Remote', 'open'),
('854913e6-6f3f-4d4e-9ac8-5b1d0169ba5b', 'Thesis Proofreading - Engineering', 'Proofread and edit a 120-page mechanical engineering thesis. Check grammar, formatting (APA 7th), and technical consistency. Track changes required.', ARRAY['Proofreading', 'Engineering', 'Academic Writing'], 4000, 12000, 7, 'Remote', 'open'),
('854913e6-6f3f-4d4e-9ac8-5b1d0169ba5b', 'MATLAB Simulation for Control Systems', 'Develop a MATLAB/Simulink model for a PID controller with step response analysis. Include documentation and parameter tuning results.', ARRAY['MATLAB', 'Simulation', 'Control Systems'], 6000, 18000, 12, 'Remote', 'open'),
('854913e6-6f3f-4d4e-9ac8-5b1d0169ba5b', 'Systematic Review Protocol Development', 'Help draft a PRISMA-compliant systematic review protocol for submission to PROSPERO. Topic: effectiveness of telemedicine in rural areas.', ARRAY['Systematic Review', 'PRISMA', 'Medicine'], 10000, 25000, 14, 'Remote', 'open'),
('854913e6-6f3f-4d4e-9ac8-5b1d0169ba5b', 'Business Plan Financial Projections', 'Create detailed 5-year financial projections for a startup business plan. Include revenue model, cost structure, break-even analysis, and sensitivity analysis.', ARRAY['Business', 'Finance', 'Excel'], 7000, 15000, 10, 'Remote', 'open'),
('854913e6-6f3f-4d4e-9ac8-5b1d0169ba5b', 'Environmental Impact Assessment Report', 'Write an environmental impact assessment for a small-scale construction project. Must follow local EPA guidelines and include mitigation strategies.', ARRAY['Environmental Science', 'Assessment', 'Report Writing'], 12000, 30000, 21, 'Remote', 'open'),
('854913e6-6f3f-4d4e-9ac8-5b1d0169ba5b', 'R Programming - Bioinformatics Analysis', 'Perform RNA-seq differential expression analysis using R (DESeq2). Data provided in FASTQ format. Need annotated results and publication-ready volcano plots.', ARRAY['R Programming', 'Bioinformatics', 'Biology'], 9000, 22000, 14, 'Remote', 'open'),
('854913e6-6f3f-4d4e-9ac8-5b1d0169ba5b', 'Legal Case Study Analysis', 'Analyze 5 landmark constitutional law cases with comparative framework. Each case needs 1500-word analysis covering facts, issues, holdings, and significance.', ARRAY['Law', 'Case Study', 'Legal Research'], 5000, 12000, 10, 'Remote', 'open'),
('854913e6-6f3f-4d4e-9ac8-5b1d0169ba5b', 'GIS Mapping for Agricultural Study', 'Create GIS maps showing crop yield distribution across 3 districts using QGIS. Data provided in shapefile format. Need thematic maps and spatial analysis.', ARRAY['GIS', 'Agriculture', 'QGIS'], 6000, 15000, 12, 'Remote', 'open'),
('854913e6-6f3f-4d4e-9ac8-5b1d0169ba5b', 'Qualitative Data Coding - NVivo', 'Code 25 interview transcripts using NVivo for a social sciences research project. Develop coding framework, identify themes, and provide codebook.', ARRAY['NVivo', 'Qualitative Research', 'Social Sciences'], 8000, 18000, 14, 'Remote', 'open'),
('854913e6-6f3f-4d4e-9ac8-5b1d0169ba5b', 'Arduino IoT Prototype Development', 'Build an Arduino-based temperature and humidity monitoring system with WiFi data logging to a cloud dashboard. Include wiring diagram and code.', ARRAY['Arduino', 'IoT', 'Electronics'], 4000, 12000, 10, 'Remote', 'open'),
('854913e6-6f3f-4d4e-9ac8-5b1d0169ba5b', 'Academic Paper Formatting - IEEE Style', 'Format a 12-page research paper to IEEE conference standards. Includes figures, tables, equations, and references. LaTeX formatting preferred.', ARRAY['LaTeX', 'IEEE', 'Formatting'], 2000, 6000, 5, 'Remote', 'open');
